class Solution {
public:
    int integerReplacement(int n) {
        int operations = 0;
        while (n != 1) {
            if (n % 2 == 0) {
                n /= 2;
            } else {
                if (n == 3 || (n & 1) == 1) {
                    n++;
                } else {
                    n--;
                }
            }
            operations++;
        }
        return operations;
    }
};
```
efficiency: HIGH
time complexity: O(log n)
space complexity: O(1)
